file.content:
const Anthropic = require('@anthropic-ai/sdk');

const anthropic = new Anthropic({
  baseURL: process.env.POLSIA_API_URL || 'https://polsia.com/api/proxy/ai',
  apiKey: process.env.POLSIA_API_KEY,
});

async function chat(message, options = {}) {
  const response = await anthropic.messages.create({
    max_tokens: options.maxTokens || 8192,
    messages: [{ role: 'user', content: message }],
    system: options.system,
  }, {
    headers: options.subscriptionId ? { 'X-Subscription-ID': options.subscriptionId } : {}
  });
  return response.content[0].text;
}

async function generateInterviewQuestions(jobTitle, jobDescription, count = 5) {
  const prompt = `Generate ${count} interview questions for a ${jobTitle} position.

Job Description:
${jobDescription || 'General ' + jobTitle + ' role'}

Return a JSON array with objects containing:
- question: The interview question
- category: behavioral/technical/situational
- difficulty: easy/medium/hard
- key_points: Array of 3-5 key points to look for in a good answer

Only return the JSON array, no other text.`;

  const response = await chat(prompt, {
    system: 'You are an expert interviewer. Generate thoughtful, role-specific interview questions. Always return valid JSON.'
  });

  try {
    return JSON.parse(response);
  } catch (e) {
    const match = response.match(/\[.*\]/s);
    if (match) {
      return JSON.parse(match[0]);
    }
    throw new Error('Failed to parse interview questions');
  }
}

async function analyzeInterviewResponse(question, response, keyPoints, options = {}) {
  const prompt = `Analyze this interview response:

Question: ${question}

Candidate's Response:
${response}

Key points to evaluate:
${keyPoints.map((p, i) => `${i + 1}. ${p}`).join('\n')}

Provide a JSON object with:
- score: 1-10 rating
- strengths: Array of 2-3 strengths
- improvements: Array of 2-3 areas for improvement
- covered_points: Array of which key points were addressed
- missed_points: Array of key points that were missed
- detailed_feedback: A 2-3 sentence constructive feedback paragraph

Only return the JSON object, no other text.`;

  const result = await chat(prompt, {
    system: 'You are an expert interview coach providing constructive, actionable feedback. Be encouraging but honest. Always return valid JSON.',
    subscriptionId: options.subscriptionId
  });

  try {
    return JSON.parse(result);
  } catch (e) {
    const match = result.match(/\{.*\}/s);
    if (match) {
      return JSON.parse(match[0]);
    }
    throw new Error('Failed to parse analysis');
  }
}

async function generateOverallFeedback(questionResults, options = {}) {
  const avgScore = questionResults.reduce((sum, r) => sum + r.score, 0) / questionResults.length;

  const prompt = `Based on these interview question results, provide overall feedback:

Results:
${questionResults.map((r, i) => `Q${i + 1}: Score ${r.score}/10 - ${r.detailed_feedback}`).join('\n\n')}

Average Score: ${avgScore.toFixed(1)}/10

Provide a JSON object with:
- overall_score: Rounded average (1-10)
- summary: 2-3 sentence overall assessment
- top_strengths: Array of 3 key strengths demonstrated
- priority_improvements: Array of 3 highest priority areas to work on
- recommended_practice: Array of 3 specific practice recommendations
- interview_readiness: "ready"/"almost_ready"/"needs_work" based on score

Only return the JSON object.`;

  const result = await chat(prompt, {
    system: 'You are a supportive career coach. Provide actionable, encouraging feedback. Always return valid JSON.',
    subscriptionId: options.subscriptionId
  });

  try {
    return JSON.parse(result);
  } catch (e) {
    const match = result.match(/\{.*\}/s);
    if (match) {
      return JSON.parse(match[0]);
    }
    return {
      overall_score: Math.round(avgScore),
      summary: 'Your interview performance has been evaluated.',
      interview_readiness: avgScore >= 7 ? 'ready' : avgScore >= 5 ? 'almost_ready' : 'needs_work'
    };
  }
}

module.exports = {
  anthropic,
  chat,
  generateInterviewQuestions,
  analyzeInterviewResponse,
  generateOverallFeedback
};

# R2 Proxy - File Storage

Upload and manage files using Polsia's R2 storage proxy. Files are stored in Cloudflare R2 with automatic CDN delivery.

## Base URL

```
https://polsia.com/api/proxy/r2
```

## Authentication

All requests require the `POLSIA_API_KEY` header:

```javascript
headers: {
  'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`
}
```

## Upload a File

**Endpoint:** `POST /upload`

**Content-Type:** `multipart/form-data`

### Node.js with node-fetch (Recommended)

**IMPORTANT:** Use `node-fetch` instead of Node's native `fetch` for file uploads. Native fetch has compatibility issues with form-data streams that cause "Unexpected end of form" errors.

```javascript
const fetch = require('node-fetch');  // IMPORTANT: Use node-fetch, not native fetch
const FormData = require('form-data');

async function uploadToR2(fileBuffer, filename, mimeType) {
  const formData = new FormData();
  formData.append('file', fileBuffer, {
    filename,
    contentType: mimeType
  });

  const response = await fetch('https://polsia.com/api/proxy/r2/upload', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
      ...formData.getHeaders()  // CRITICAL: includes Content-Type with boundary
    },
    body: formData
  });

  const result = await response.json();
  if (!result.success) {
    throw new Error(result.error?.message || 'Upload failed');
  }
  return result.file.url;
}
```

### With Express + Multer

```javascript
const fetch = require('node-fetch');  // IMPORTANT: Use node-fetch
const multer = require('multer');
const FormData = require('form-data');

const upload = multer({ storage: multer.memoryStorage() });

app.post('/api/products', upload.single('image'), async (req, res) => {
  let imageUrl = null;

  if (req.file) {
    const formData = new FormData();
    formData.append('file', req.file.buffer, {
      filename: req.file.originalname,
      contentType: req.file.mimetype
    });

    const uploadRes = await fetch('https://polsia.com/api/proxy/r2/upload', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
        ...formData.getHeaders()
      },
      body: formData
    });

    const result = await uploadRes.json();
    if (result.success) {
      imageUrl = result.file.url;
    }
  }

  // Save product with imageUrl...
});
```

### Common Mistakes

```javascript
// WRONG #1 - Using native fetch (causes "Unexpected end of form" error)
const response = await fetch(url, { ... });  // Native fetch breaks form-data streams

// CORRECT - Use node-fetch
const fetch = require('node-fetch');
const response = await fetch(url, { ... });

// WRONG #2 - Missing formData.getHeaders()
const response = await fetch(url, {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'multipart/form-data'  // NO! Missing boundary
  },
  body: formData
});

// CORRECT - Use formData.getHeaders()
const response = await fetch(url, {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    ...formData.getHeaders()  // Includes Content-Type WITH boundary
  },
  body: formData
});
```

## Response Format

```json
{
  "success": true,
  "file": {
    "id": "uuid",
    "key": "company_123/abc123_image.jpg",
    "url": "https://cdn.polsia.com/company_123/abc123_image.jpg",
    "filename": "image.jpg",
    "mime_type": "image/jpeg",
    "size": 102400,
    "created_at": "2025-01-08T12:00:00Z"
  }
}
```

## List Files

```javascript
const response = await fetch('https://polsia.com/api/proxy/r2/files?limit=50', {
  headers: { 'Authorization': `Bearer ${process.env.POLSIA_API_KEY}` }
});
const { files, pagination } = await response.json();
```

## Delete File

```javascript
await fetch(`https://polsia.com/api/proxy/r2/files/${fileKey}`, {
  method: 'DELETE',
  headers: { 'Authorization': `Bearer ${process.env.POLSIA_API_KEY}` }
});
```

## Allowed File Types

- **Images:** jpeg, png, gif, webp
- **Videos:** mp4, webm, mov, avi, mpeg
- **Audio:** mp3, wav, ogg, m4a, aac, flac
- **Documents:** pdf, docx, pptx, xlsx, txt, csv

## Size Limits

- Images: 20MB
- Videos: 1GB
- Audio: 500MB
- Documents: 50MB

## Dependencies

Add to package.json:
```json
"node-fetch": "^2.7.0",
"form-data": "^4.0.0",
"multer": "^1.4.5-lts.1"
```

**Note:** Use `node-fetch` v2.x (not v3.x) for CommonJS compatibility.

